FILE* open_log_file(const char* filename) {
    if (!filename) {
        fprintf(stderr, "Error: NULL filename provided\n");
        return NULL;
    }
    
    FILE* logfile = fopen(filename, "a");
    if (!logfile) {
        fprintf(stderr, "Error: Failed to open log file: %s\n", filename);
        return NULL;
    }
    
    return logfile;
}

void close_log_file(FILE* logfile) {
    if (logfile) {
        fflush(logfile);
        fclose(logfile);
    }
}